import { X, Info } from 'lucide-react';
import type { CountryData } from '../types';
import { formatFullNumber, formatNumber } from '../lib/format';
import { getFlag } from '../lib/countries';

interface CountryModalProps {
  country: CountryData;
  onClose: () => void;
  type: 'origin' | 'host';
  dataPeriod: string;
}

const BAR_COLORS = {
  refugees: { bg: 'bg-red-900/60', bar: 'bg-red-700', text: 'text-red-400' },
  asylum_seekers: { bg: 'bg-amber-900/40', bar: 'bg-amber-700', text: 'text-amber-400' },
  idps: { bg: 'bg-orange-900/40', bar: 'bg-orange-700', text: 'text-orange-400' },
  stateless: { bg: 'bg-stone-800/60', bar: 'bg-stone-600', text: 'text-stone-400' },
};

export default function CountryModal({ country, onClose, type, dataPeriod }: CountryModalProps) {
  const flag = getFlag(country.code);
  const categories = [
    { key: 'refugees', label: 'Refugees', value: country.refugees },
    { key: 'idps', label: 'Internally Displaced', value: country.idps },
    { key: 'asylum_seekers', label: 'Asylum Seekers', value: country.asylum_seekers },
    { key: 'stateless', label: 'Stateless Persons', value: country.stateless },
  ].filter(c => c.value > 0);

  const maxVal = Math.max(...categories.map(c => c.value), 1);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm"
      onClick={onClose}>
      <div
        className="bg-zinc-900 border border-zinc-700 w-full max-w-md mx-4 shadow-2xl"
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-4 py-3 border-b border-zinc-800">
          <div className="flex items-center gap-2">
            <span className="text-xl">{flag}</span>
            <div>
              <h3 className="text-sm font-semibold text-zinc-100">{country.name}</h3>
              <span className="text-[10px] text-zinc-500 uppercase tracking-wider">
                {type === 'origin' ? 'Country of Origin' : 'Host Country'}
                {' · '}{dataPeriod}
              </span>
            </div>
          </div>
          <button
            onClick={onClose}
            className="p-1 hover:bg-zinc-800 transition-colors text-zinc-400 hover:text-zinc-200"
          >
            <X className="w-4 h-4" />
          </button>
        </div>

        {/* Total */}
        <div className="px-4 py-3 border-b border-zinc-800/50">
          <div className="text-[10px] text-zinc-500 uppercase tracking-wider">Total Displaced Persons</div>
          <div className="text-2xl font-bold text-zinc-100 mt-0.5">{formatFullNumber(country.total)}</div>
          <div className="text-[10px] text-zinc-500 mt-0.5">{formatNumber(country.total)}</div>
        </div>

        {/* Breakdown */}
        <div className="px-4 py-3 space-y-3">
          <div className="text-[10px] text-zinc-500 uppercase tracking-wider">Population Breakdown</div>
          {categories.map(cat => {
            const colors = BAR_COLORS[cat.key as keyof typeof BAR_COLORS];
            const pct = (cat.value / maxVal) * 100;
            const totalPct = country.total > 0 ? ((cat.value / country.total) * 100).toFixed(1) : '0';
            return (
              <div key={cat.key}>
                <div className="flex items-center justify-between mb-1">
                  <span className={`text-xs ${colors.text}`}>{cat.label}</span>
                  <span className="text-xs text-zinc-300">{formatFullNumber(cat.value)}</span>
                </div>
                <div className={`h-2.5 w-full ${colors.bg}`}>
                  <div
                    className={`h-full ${colors.bar} transition-all duration-500`}
                    style={{ width: `${pct}%` }}
                  />
                </div>
                <div className="text-[9px] text-zinc-600 mt-0.5">{totalPct}% of total</div>
              </div>
            );
          })}
        </div>

        {/* Footer */}
        <div className="px-4 py-2 border-t border-zinc-800 flex items-start gap-1.5">
          <Info className="w-3 h-3 text-zinc-600 mt-0.5 shrink-0" />
          <span className="text-[9px] text-zinc-600 leading-relaxed">
            Data: UNHCR Population Statistics · {dataPeriod} estimates.
            Country-level data reflects the latest full-year figures available in the UNHCR API.
          </span>
        </div>
      </div>
    </div>
  );
}

